import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate } from 'react-router-dom';
import Navbar from './components/Navbar/Navbar';
import Footer from './components/Footer/Footer';
import Hero from './features/landing/Hero';
import HowItWorks from './features/landing/HowItWorks';
import JobServices from './features/landing/JobServices';
import Testimonials from './features/landing/Testimonials';
import CTA from './features/landing/CTA';
import JobListContainer from './features/eksplorasi/JobListContainer';
import Login from './components/auth/Login';
import Register from './components/auth/Register';

// Komponen pembantu tetap di luar agar tidak terpicu re-render berlebih
const ViewAllButton = () => {
    const navigate = useNavigate();
    return (
        <div style={{ textAlign: 'center', marginTop: '40px' }}>
            <button 
                onClick={() => navigate('/eksplorasi')} 
                style={{ padding: '14px 40px', background: '#ea580c', color: '#fff', border: 'none', borderRadius: '12px', fontWeight: '800', cursor: 'pointer' }}
            >
                Semua Lowongan
            </button>
        </div>
    );
};

const App = () => {
    const [isAuthenticated, setIsAuthenticated] = useState(!!localStorage.getItem('token'));
    const [activeMenu, setActiveMenu] = useState('eksplorasi');
    const navigate = useNavigate(); // Hook harus dipanggil di dalam komponen

    // Definisi fungsi di dalam komponen agar bisa mengakses navigate dan setActiveMenu
    const handleNavigation = (menu) => {
        setActiveMenu(menu);
        if (menu === 'eksplorasi') navigate('/eksplorasi');
        if (menu === 'home') navigate('/');
    };

    const handleLogout = () => {
        localStorage.removeItem('token');
        setIsAuthenticated(false);
        navigate('/login');
    };

    return (
        <div className="flex flex-col min-h-screen bg-black text-white">
            <Navbar 
                isAuthenticated={isAuthenticated} 
                activeMenu={activeMenu} 
                setActiveMenu={handleNavigation} 
                handleLogout={handleLogout}
            />

            <main className="flex-grow">
                <Routes>
                    <Route path="/" element={
                        <>
                            {!isAuthenticated && (
                                <>
                                    <Hero />
                                    <HowItWorks />
                                    <JobServices />
                                    <Testimonials />
                                    <CTA />
                                </>
                            )}
                            <div className="p-10">
                                <h2 className="text-2xl font-bold mb-6">Lowongan Terbaru</h2>
                                <JobListContainer limit={3} />
                                <ViewAllButton />
                            </div>
                        </>
                    } />
                    <Route path="/eksplorasi" element={
                        <div className="p-10">
                            <h1 className="text-3xl font-bold mb-6">Seluruh Lowongan Kerja</h1>
                            <JobListContainer />
                        </div>
                    } />
                    <Route path="/login" element={<Login onLoginSuccess={() => setIsAuthenticated(true)} />} />
                    <Route path="/register" element={<Register />} />
                </Routes>
            </main>
            <Footer />
        </div>
    );
};

// Bungkus App dengan Router di level export
const AppWrapper = () => (
    <Router>
        <App />
    </Router>
);

export default AppWrapper;
